return items.map((item) => {
  const body = item.json.body ?? item.json;
  const missing = [];
  for (const field of ['requestId', 'taskType', 'payload']) {
    if (body[field] === undefined || body[field] === null || body[field] === '') {
      missing.push(field);
    }
  }

  if (missing.length > 0) {
    return {
      json: {
        accepted: false,
        status: 'rejected',
        missing,
        message: `Missing required fields: ${missing.join(', ')}`
      }
    };
  }

  return {
    json: {
      accepted: true,
      status: 'queued',
      jobId: `job_${Date.now()}_${String(body.requestId).replace(/[^a-zA-Z0-9_-]/g, '_')}`,
      requestId: body.requestId,
      taskType: body.taskType,
      payloadPreview: body.payload,
      next: 'Persist this job to Airtable, Postgres, Google Sheets, or your queue table before doing slow work.'
    }
  };
});
